external_knowledge:
- 'big hospitals' refers to hospitals with more than 1000 beds;
- 'government hospitals' indicates the ownership is categorized as 'Government';
- 'the start of their websites' refers to the first 10 characters of the hospital's website URL;
- 'count of unique visitors' is derived from counting distinct user IDs in the access logs for each hospital.

sql:
SELECT COUNT(provider_id) AS num_hospitals, county_name
FROM hospitals
GROUP BY county_name;

SELECT hospital_name, address, city, state, zip_code, phone_number, website_url
FROM hospitals
WHERE county_name = 'Your County Name';

SELECT state, COUNT(*) as num_hospitals
FROM hospitals
GROUP BY state;

external_knowledge:
- 'medical facilities' refers to 'hospitals';
- 'emergency care spots' refers to 'emergency services';
- 'area' refers to 'county';
- 'places' refers to 'counties';
- 'individuals' refers to 'users'.

sql:
SELECT state, county_name, COUNT(provider_id) AS hospital_count
FROM hospitals
GROUP BY state, county_name;

external_knowledge:
- "spacious hospitals" refers to hospitals with a high number of beds;
- "populous counties" refers to counties with a population greater than 10,000;
- "emergency care" indicates that the hospital offers emergency services.

sql:
SELECT * 
FROM emergency_services 
WHERE service_id = 10;

SELECT hospitals.hospital_name, counties.county_name 
FROM hospitals 
JOIN counties ON hospitals.county_name = counties.county_name;

SELECT h.hospital_name, h.address, h.city, h.state, h.number_of_beds, TANH(h.latitude) AS tanh_latitude, TANH(h.longitude) AS tanh_longitude, ht.type_name
FROM hospitals h
JOIN hospital_types ht ON h.hospital_type = ht.type_id;

SELECT COUNT(*) AS surgical_service_count
FROM hospital_services
WHERE service_name = 'Surgical';
